  logger.error('Unhandled error', {
    message: err.message,
    path: req.path,
    method: req.method,
    stack: NODE_ENV === 'production' ? undefined : err.stack,
  });

  res.status(err.status || 500).json({
    error: NODE_ENV === 'production' 
      ? 'Internal server error' 
      : err.message,
  });
});

app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ==================== SERVER START ====================
